// // This module implements a 5-bit wide, 2-to-1 demultiplexer. When the select signal `s` is 0, the output `y` is set to the value of input `a1`; when `s` is 1, the output `y` takes the value from input `a0`. //
module top_module(a0, a1, s, y);input [4:0] a0, a1;
  input s;
  output [4:0] y;
  assign y = s ? a1 : a0;
endmodule
